def confirm(question):
    if FORCE_YES:
        return True

    while True:
        answer = input(question + " <Yes|No> ").lower()

        if answer == "yes" or answer == "y":
            confirmed = True
            break
        if answer == "no" or answer == "n":
            confirmed = False
            break

    return confirmed


[GRAPH] mackup.utils.copy
def copy(src, dst):
    assert isinstance(src, str)
    assert os.path.exists(src)
    assert isinstance(dst, str)

    abs_path = os.path.dirname(os.path.abspath(dst))
    if not os.path.isdir(abs_path):
        os.makedirs(abs_path)

    if os.path.isfile(src):
        shutil.copy(src, dst)

    elif os.path.isdir(src):
        shutil.copytree(src, dst)

    else:
        raise ValueError("Unsupported file: {}".format(src))

    chmod(dst)


[GRAPH] mackup.utils.delete
def delete(filepath):
    remove_acl(filepath)

    remove_immutable_attribute(filepath)

    if os.path.isfile(filepath) or os.path.islink(filepath):
        os.remove(filepath)
    elif os.path.isdir(filepath):
        shutil.rmtree(filepath)


[GRAPH] mackup.utils.link
def link(target, link_to):
    assert isinstance(target, str)
    assert os.path.exists(target)
    assert isinstance(link_to, str)

    abs_path = os.path.dirname(os.path.abspath(link_to))
    if not os.path.isdir(abs_path):
        os.makedirs(abs_path)

    chmod(target)

    os.symlink(target, link_to)


