def delete(filepath):
    remove_acl(filepath)

    remove_immutable_attribute(filepath)

    if os.path.isfile(filepath) or os.path.islink(filepath):
        os.remove(filepath)
    elif os.path.isdir(filepath):
        shutil.rmtree(filepath)


